//! C-interface for the component.
//! This code must be unsafe.
//! Assumptions about correctness are introduced and need to be verified by other means.

use data::*;

#[cfg(test)]
use std::sync::Mutex;

#[cfg(not(test))]
extern "C" {
  fn get_read_port1() -> bool;
  fn get_read_port2() -> bool;
}

pub fn unsafe_get_read_port1() -> bool
{
  unsafe {
    return get_read_port1();
  }
}

pub fn unsafe_get_read_port2() -> bool
{
  unsafe {
    return get_read_port2();
  }
}

//////////////////////////////////////////////////////////////////////////////////
// Testing Versions
//////////////////////////////////////////////////////////////////////////////////

#[cfg(test)]
lazy_static::lazy_static! {
  // simulate the global C variables that point to the microkit shared memory regions.  In a full
  // microkit system we would be able to mutate the shared memory for out ports since they're r/w,
  // but we couldn't do that for in ports since they are read-only
  pub static ref IN_read_port1: Mutex<Option<u8>> = Mutex::new(None);
  pub static ref IN_read_port2: Mutex<Option<u8>> = Mutex::new(None);
}

#[cfg(test)]
pub fn initialize_test_globals() {
  unsafe {
    *IN_read_port1.lock().unwrap_or_else(|e| e.into_inner()) = None;
    *IN_read_port2.lock().unwrap_or_else(|e| e.into_inner()) = None;
  }
}

#[cfg(test)]
pub fn get_read_port1() -> bool
{
  unsafe {
    match *IN_read_port1.lock().unwrap_or_else(|e| e.into_inner()) {
      Some(v) => {
        return true;
      },
      None => return false,
    }
  }
}

#[cfg(test)]
pub fn get_read_port2() -> bool
{
  unsafe {
    match *IN_read_port2.lock().unwrap_or_else(|e| e.into_inner()) {
      Some(v) => {
        return true;
      },
      None => return false,
    }
  }
}
